+  function writeAuthProfileStore(agentDir: string, profiles: Record<string, unknown>): void {
+    fs.writeFileSync(
+      path.join(agentDir, "auth-profiles.json"),
+      `${JSON.stringify({ version: AUTH_STORE_VERSION, profiles }, null, 2)}\n`,
+      "utf8",
