+  function loadAuthProfile(agentDir: string, profileId: string): AuthProfileCredential {
+    clearRuntimeAuthProfileStoreSnapshots();
+    const store = ensureAuthProfileStore(agentDir);
+    const profile = store.profiles[profileId];
